1	/// Splits a chat message into segments so we can render fenced code blocks and
2	/// reasoning blocks ourselves while still letting `egui_commonmark` handle the
3	/// surrounding prose.
4	///
5	/// Why pre-split instead of forking the renderer: `egui_commonmark` 0.23
6	/// doesn't expose a code-block hook, and fenced code blocks are 99% of the
7	/// custom rendering we want anyway (per-block copy, language pill, reasoning
8	/// collapse).
9	#[derive(Debug, PartialEq)]
10	pub enum Segment<'a> {
11	    /// Plain markdown prose to feed back into the CommonMark renderer.
12	    Markdown(&'a str),
13	    /// Fenced code block. `lang` is the info string after the opening fence
14	    /// (often a language name; sometimes a filename or empty).
