                        let run = run_len(bytes, j, fence_char);
                        if run >= fence_len {
                            // Closing fences must not contain info text on the
                            // same line per CommonMark, but be lenient.
                            close_start = Some(j);
                            close_end = Some(
                                bytes[j..]
